    private void SButton3ActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_SButton3ActionPerformed
    String currentUserID = "S0001"; // Example - get this from your login system
    
    // 2. Find student name from enrollment file
    String studentName = null;
    try (BufferedReader enrollReader = new BufferedReader(new FileReader("student_enroll.txt"))) {
        enrollReader.readLine(); // Skip header
        String line;
        while ((line = enrollReader.readLine()) != null) {
            String[] parts = line.split("\\s*,\\s*");
            if (parts.length > 1 && currentUserID.equalsIgnoreCase(parts[0].trim())) {
                studentName = parts[1].trim();
                break;
            }
        }
    } catch (IOException e) {
        JOptionPane.showMessageDialog(this, 
            "Error reading student records: " + e.getMessage(),
            "File Error", JOptionPane.ERROR_MESSAGE);
        return;
    }

    if (studentName == null) {
        JOptionPane.showMessageDialog(this, 
            "No student found with ID: " + currentUserID,
            "Not Found", JOptionPane.WARNING_MESSAGE);
        return;
    }

    // 3. Check payment status
    StringBuilder paymentInfo = new StringBuilder();
    boolean paymentFound = false;
    
    try (BufferedReader paymentReader = new BufferedReader(new FileReader("py_status.txt"))) {
        paymentReader.readLine(); // Skip header
        String line;
        while ((line = paymentReader.readLine()) != null) {
            String[] parts = line.split("\\s*,\\s*");
            if (parts.length >= 4 && studentName.equalsIgnoreCase(parts[0].trim())) {
                paymentFound = true;
                paymentInfo.append("Payment Details:\n")
                           .append("Name: ").append(parts[0]).append("\n")
                           .append("Amount Payable: RM").append(parts[1]).append("\n")
                           .append("Amount Paid: RM").append(parts[2]).append("\n")
                           .append("Status: ").append(parts[3]).append("\n\n");
            }
        }
    } catch (IOException e) {
        JOptionPane.showMessageDialog(this, 
            "Error reading payment records: " + e.getMessage(),
            "File Error", JOptionPane.ERROR_MESSAGE);
        return;
    }

    // 4. Show results
    if (paymentFound) {
        JOptionPane.showMessageDialog(this, 
            paymentInfo.toString(),
            "Payment Status for " + studentName, 
            JOptionPane.INFORMATION_MESSAGE);
    } else {
        JOptionPane.showMessageDialog(this, 
            "No payment records found for " + studentName,
            "No Records", JOptionPane.WARNING_MESSAGE);
    }
    }//GEN-LAST:event_SButton3ActionPerformed

    private void SButton5ActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_SButton5ActionPerformed
        int response = JOptionPane.showConfirmDialog(
        this, 
        "Are you sure you want to exit the system?",
        "Exit Confirmation",
        JOptionPane.YES_NO_OPTION,
        JOptionPane.QUESTION_MESSAGE);
    
    // If user clicked Yes
    if (response == JOptionPane.YES_OPTION) {
        // Close the current window
        this.dispose();
        
        // Or exit the entire application
        System.exit(0);
    }
    }//GEN-LAST:event_SButton5ActionPerformed

